import{_ as t,o as a,c as i,ag as l}from"./chunks/framework.BqfgOMAh.js";const u=JSON.parse('{"title":"Widget Skill","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/widget-skill.md","filePath":"zh/guide/widget-skill.md"}'),d={name:"zh/guide/widget-skill.md"};function n(r,e,s,o,p,c){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="widget-skill" tabindex="-1">Widget Skill <a class="header-anchor" href="#widget-skill" aria-label="Permalink to &quot;Widget Skill&quot;">​</a></h1><p>Widget Skill 是 NexusFlow 0.2.0 中可试用的 UMG Widget Blueprint 能力。它面向 HUD、面板、菜单、状态栏等 UI 资产，帮助 Agent 通过结构化定义创建和修改 Widget Blueprint。</p><blockquote><p>当前为 MVP / 实验性能力。建议从小型 UI、局部修改和可读回验证的任务开始使用。</p></blockquote><h2 id="能做什么" tabindex="-1">能做什么 <a class="header-anchor" href="#能做什么" aria-label="Permalink to &quot;能做什么&quot;">​</a></h2><ul><li>从零创建 Widget Blueprint。</li><li>读取已有 Widget Blueprint 的结构和布局信息。</li><li>修改已有控件的文本、颜色、百分比、slot、事件声明或绑定声明。</li><li>重写完整 Designer 或某个容器分支。</li><li>在可用时捕获真实 Widget 预览截图。</li><li>与 Blueprint Skill 配合，为 Widget 添加事件、变量、函数和 EventGraph 逻辑。</li></ul><h2 id="主要动作" tabindex="-1">主要动作 <a class="header-anchor" href="#主要动作" aria-label="Permalink to &quot;主要动作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>动作</th><th>用途</th></tr></thead><tbody><tr><td><code>generate_widget_blueprint</code></td><td>创建完整 Widget Blueprint</td></tr><tr><td><code>read_widget_blueprint</code></td><td>读取结构、布局和诊断信息</td></tr><tr><td><code>write_widget_tree</code></td><td>替换完整 Designer 或指定容器分支</td></tr><tr><td><code>patch_widget_tree</code></td><td>修改已有控件的属性级信息</td></tr><tr><td><code>capture_widget_preview</code></td><td>捕获真实预览截图</td></tr></tbody></table><h2 id="推荐流程" tabindex="-1">推荐流程 <a class="header-anchor" href="#推荐流程" aria-label="Permalink to &quot;推荐流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 确认目标 UI 类型和 viewport 尺寸。</span></span>
<span class="line"><span>2. 用根 Canvas 放少量区域容器，例如 Header、Content、Footer、Modal。</span></span>
<span class="line"><span>3. 区域内部使用 Border、VerticalBox、HorizontalBox、ScrollBox、SizeBox 等容器排版。</span></span>
<span class="line"><span>4. 为重要控件设置稳定 id；交互控件设置 variable.is_variable=true。</span></span>
<span class="line"><span>5. 执行 generate_widget_blueprint 或 write_widget_tree。</span></span>
<span class="line"><span>6. 使用 read_widget_blueprint 读回结构与布局诊断。</span></span>
<span class="line"><span>7. 如需事件或绑定，再用 Blueprint Skill 补充 Graph 逻辑。</span></span>
<span class="line"><span>8. 编译、保存或截图验证。</span></span></code></pre></div><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>Widget Tree 和 Blueprint Graph 是两层概念：Designer 控件写在 <code>widget_tree</code>，事件、函数、变量和图逻辑写在 Blueprint 通用定义中。</li><li>Canvas 只适合放区域容器，不建议把大量 TextBlock/Button 直接散放在根 Canvas 下。</li><li><code>patch_widget_tree</code> 适合属性级小改；层级变化请使用 <code>write_widget_tree</code>。</li><li>写入成功不等于最终状态正确，必须通过 <code>read_widget_blueprint</code> 或截图读回验证。</li><li>复杂 UI 建议先生成静态结构，再逐步添加交互逻辑。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./mcp">在 IDE / Agent 中使用 NexusFlow</a>：从外部 IDE 使用 Widget Skill。</li><li><a href="./blueprint-operations">蓝图操作</a>：了解通用 Blueprint Graph 能力。</li></ul>`,13)])])}const g=t(d,[["render",n]]);export{u as __pageData,g as default};
